calcFn:
var f = parseFloat(aperture);
    var t = parseFloat(shutter);
    var isoVal = parseFloat(iso);
    var ev100 = Math.log2(f * f / t) - Math.log2(isoVal / 100);
    var luxApprox = Math.pow(2, ev100) * 2.5;
    var scene = 'Unknown';
    if (ev100 >= 15) scene = 'Bright sun on snow/sand';
    else if (ev100 >= 13) scene = 'Bright daylight';
    else if (ev100 >= 11) scene = 'Hazy sun / Overcast bright';
    else if (ev100 >= 9) scene = 'Overcast / Open shade';
    else if (ev100 >= 7) scene = 'Indoor, well-lit';
    else if (ev100 >= 5) scene = 'Indoor, average lighting';
    else if (ev100 >= 3) scene = 'Dim indoor / Dusk';
    else if (ev100 >= 1) scene = 'Twilight / Candle-lit room';
    else scene = 'Night / Very dark';
    document.getElementById('ev').textContent = 'EV ' + fmt(ev100, 1);
    document.getElementById('lux').textContent = fmt(luxApprox, 0) + ' lux';
    document.getElementById('scene').textContent = scene;

var phi = 1.6180339887;
    var longVal, shortVal;
    if (mode === 'longer') { shortVal = value; longVal = value * phi; }
    else if (mode === 'shorter') { longVal = value; shortVal = value / phi; }
    else { longVal = value / (1 + 1/phi); shortVal = value - longVal; }
    document.getElementById('longSide').textContent = fmt(longVal, 2);
    document.getElementById('shortSide').textContent = fmt(shortVal, 2);
    document.getElementById('ratio').textContent = fmt(longVal / shortVal, 10) + ' (φ = 1.6180339887...)';
    document.getElementById('spiralPoints').textContent = 'Place subject at ' + fmt(longVal * 0.382, 1) + ' or ' + fmt(longVal * 0.618, 1) + ' from edge';

var isoVal = parseFloat(iso);
    var isoFactor = Math.sqrt(isoVal / 100);
    var effectGN = guideNumber * isoFactor;
    var dist = effectGN / aperture;
    var reqF = effectGN / 5;
    document.getElementById('maxDist').textContent = fmt(dist, 1) + ' m (' + fmt(dist * 3.281, 1) + ' ft)';
    document.getElementById('reqAperture').textContent = 'f/' + fmt(reqF, 1);
    document.getElementById('effectiveGN').textContent = fmt(effectGN, 1) + ' (at ISO ' + isoVal + ')';

var cf = parseFloat(cropFactor);
    var equiv = focalLength * cf;
    var equivAp = maxAperture * cf;
    var fovRad = 2 * Math.atan(36 / (2 * equiv));
    var fovDeg = fovRad * 180 / Math.PI;
    var minShut = 1 / equiv;
    var shutStr = equiv <= 1 ? fmt(1/minShut, 0) + 's' : '1/' + fmt(equiv, 0) + 's';
    document.getElementById('equivFL').textContent = fmt(equiv, 0) + 'mm equivalent';
    document.getElementById('equivAperture').textContent = 'f/' + fmt(equivAp, 1) + ' (depth of field equivalent)';
    document.getElementById('fov').textContent = fmt(fovDeg, 1) + '°';
    document.getElementById('minShutter').textContent = shutStr + ' (reciprocal rule)';

var bits = parseInt(bitDepth);
    var fmt2 = format;
    var pixels = megapixels * 1000000;
    var bytesPerPixel;
    if (fmt2 === 'rawUncomp') bytesPerPixel = bits * 3 / 8;
    else if (fmt2 === 'raw') bytesPerPixel = bits * 3 / 8 * 0.6;
    else if (fmt2 === 'jpeg_high') bytesPerPixel = 0.75;
    else if (fmt2 === 'jpeg_med') bytesPerPixel = 0.35;
    else if (fmt2 === 'tiff') bytesPerPixel = bits * 3 / 8;
    else bytesPerPixel = bits * 3 / 8 * 0.5;
    var fileSizeBytes = pixels * bytesPerPixel;
    var fileSizeMB = fileSizeBytes / (1024 * 1024);
    var totalMB = fileSizeMB * numPhotos;
    var totalGB = totalMB / 1024;
    var fitsOn64 = Math.floor(64 * 1024 / fileSizeMB);
    var sizeStr = fileSizeMB >= 1 ? fmt(fileSizeMB, 1) + ' MB' : fmt(fileSizeBytes / 1024, 0) + ' KB';
    var totalStr = totalGB >= 1 ? fmt(totalGB, 2) + ' GB' : fmt(totalMB, 0) + ' MB';
    document.getElementById('fileSize').textContent = sizeStr;
    document.getElementById('totalSize').textContent = totalStr;
    document.getElementById('cardsNeeded').textContent = fmt(fitsOn64, 0) + ' photos';

var equiv = focalLength * cropFactor;
    var motionFactor = 1;
    if (subjectMotion === 'slow') motionFactor = 2;
    else if (subjectMotion === 'moderate') motionFactor = 4;
    else if (subjectMotion === 'fast') motionFactor = 8;
    var isStops = parseInt(stabilization);
    var minSpeed = equiv * motionFactor;
    var withStab = minSpeed / Math.pow(2, isStops);
    var rec;
    if (minSpeed >= 1000) rec = 'Use fast glass (f/2.8+) and high ISO. Flash may help freeze motion.';
    else if (minSpeed >= 250) rec = 'Good light or ISO 400-1600 needed. Continuous AF recommended.';
    else if (minSpeed >= 60) rec = 'Standard conditions. Most cameras handle this easily.';
    else rec = 'Tripod recommended for best results at this slow speed.';
    function shutterStr(s) { return s >= 1 ? fmt(s, 0) + 's' : '1/' + fmt(s, 0) + 's'; }
    document.getElementById('minShutter').textContent = shutterStr(minSpeed);
    document.getElementById('withIS').textContent = shutterStr(withStab);
    document.getElementById('recommendation').textContent = rec;

var areaSqIn = jointLength * jointWidth * numJoints * 2;
    var coveragePerOz, openTime, clampTime;
    if (glueType === 'pva') { coveragePerOz = 25; openTime = '5-10 min'; clampTime = '30-60 min'; }
    else if (glueType === 'polyurethane') { coveragePerOz = 20; openTime = '15-20 min'; clampTime = '1-2 hours'; }
    else if (glueType === 'epoxy') { coveragePerOz = 15; openTime = '5-30 min (varies)'; clampTime = '4-24 hours'; }
    else { coveragePerOz = 22; openTime = '5-10 min'; clampTime = '45-90 min'; }
    var ozNeeded = areaSqIn / coveragePerOz;
    var mlNeeded = ozNeeded * 29.574;
    document.getElementById('totalArea').textContent = fmt(areaSqIn, 1) + ' sq in (' + fmt(areaSqIn * 6.452, 0) + ' cm²)';
    document.getElementById('glueNeeded').textContent = fmt(ozNeeded, 1) + ' oz (' + fmt(mlNeeded, 0) + ' mL)';
    document.getElementById('openTime').textContent = openTime;
    document.getElementById('clampTime').textContent = clampTime;

var interior = (numSides - 2) * 180 / numSides;
    var miter = (180 - interior) / 2;
    var tilt = tiltAngle * Math.PI / 180;
    var miterRad = miter * Math.PI / 180;
    var compMiter, compBevel;
    if (tiltAngle === 0) {
      compMiter = miter;
      compBevel = 0;
    } else {
      compMiter = Math.atan(Math.sin(miterRad) * Math.cos(tilt)) * 180 / Math.PI;
      compBevel = Math.atan(Math.cos(miterRad) * Math.sin(tilt)) * 180 / Math.PI;
    }
    document.getElementById('miterAngle').textContent = fmt(compMiter, 2) + '°';
    document.getElementById('bevelAngle').textContent = fmt(compBevel, 2) + '°';
    document.getElementById('bladeAngle').textContent = fmt(90 - compMiter, 2) + '° from fence';
    document.getElementById('interiorAngle').textContent = fmt(interior, 2) + '°';

var tangentialPct = parseFloat(species);
    var mcChange = mcStart - mcEnd;
    var shrinkPct = tangentialPct * (mcChange / 19);
    var shrinkInches = boardWidth * (shrinkPct / 100);
    var newW = boardWidth - shrinkInches;
    var seasonalRange = boardWidth * (tangentialPct / 100) * (4 / 19);
    document.getElementById('shrinkage').textContent = fmt(Math.abs(shrinkInches), 4) + '" (' + fmt(Math.abs(shrinkInches) * 25.4, 2) + ' mm)';
    document.getElementById('newWidth').textContent = fmt(newW, 4) + '"';
    document.getElementById('pctChange').textContent = fmt(Math.abs(shrinkPct), 2) + '% ' + (mcChange > 0 ? 'shrinkage' : 'expansion');
    document.getElementById('gapAdvice').textContent = '±' + fmt(seasonalRange / 2, 3) + '" per ' + fmt(boardWidth, 1) + '" of width';

var usable = boardWidth - 2 * pinWidth;
    var tailSpacing = usable / numTails;
    var thickness = 0.75;
    var ratio = parseInt(tailAngle);
    var slopeOffset = thickness / ratio;
    var tailWide = tailSpacing - 2 * slopeOffset + 2 * slopeOffset;
    var pinNarrow = tailSpacing - tailWide + slopeOffset;
    var marks = [];
    marks.push(fmt(pinWidth, 3) + '"');
    for (var i = 0; i < numTails; i++) {
      var pos = pinWidth + i * tailSpacing;
      marks.push(fmt(pos, 3) + '"');
    }
    marks.push(fmt(boardWidth - pinWidth, 3) + '"');
    document.getElementById('tailWidth').textContent = fmt(tailSpacing, 3) + '"';
    document.getElementById('pinSpacing').textContent = fmt(tailSpacing, 3) + '" on center';
    document.getElementById('layoutMarks').textContent = marks.join(', ');
    document.getElementById('pinNarrow').textContent = 'Ratio 1:' + ratio + ' (angle: ' + fmt(Math.atan(1/ratio)*180/Math.PI, 1) + '°)';

var coveragePerQt = parseFloat(finishType);
    var totalSqFt = sqft * coats * (1 + wastePct / 100);
    var qts = totalSqFt / coveragePerQt;
    var gals = qts / 4;
    var buyGal = Math.ceil(gals);
    var buyQt = Math.ceil(qts);
    var bestBuy = (buyGal <= buyQt / 3) ? buyGal + ' gallon(s)' : buyQt + ' quart(s)';
    document.getElementById('quartsNeeded').textContent = fmt(qts, 1) + ' quarts';
    document.getElementById('gallonsNeeded').textContent = bestBuy;
    document.getElementById('totalCoverage').textContent = fmt(totalSqFt, 0) + ' sq ft total';

var bf = (thickness * width * length) / 144;
    var totalBF = bf * numBoards;
    var total = totalBF * pricePerBF;
    var costPer = total / numBoards;
    document.getElementById('boardFeet').textContent = fmt(bf, 2) + ' BF';
    document.getElementById('totalBF').textContent = fmt(totalBF, 2) + ' BF';
    document.getElementById('totalCost').textContent = dollar(total);
    document.getElementById('costPerBoard').textContent = dollar(costPer);

var gauge = parseInt(screwGauge);
    var shankDia = 0.060 + gauge * 0.013;
    var rootDia = shankDia * 0.65;
    var pilotSoft = rootDia * 0.85;
    var pilotHard = rootDia * 1.0;
    var pilot = woodType === 'hard' ? pilotHard : pilotSoft;
    var clearance = shankDia + 0.01;
    var counter = shankDia * 2;
    var recLength = materialThickness + (materialThickness * 1.5);
    recLength = Math.ceil(recLength * 4) / 4;
    function toFraction(n) {
      var sixteenths = Math.round(n * 16);
      if (sixteenths % 16 === 0) return (sixteenths/16) + '"';
      if (sixteenths % 8 === 0) return (sixteenths/16) + '" (' + (sixteenths/8) + '/2")';
      if (sixteenths % 4 === 0) return (sixteenths/16).toFixed(3) + '" (' + (sixteenths/4) + '/4")';
      return (sixteenths/16).toFixed(3) + '" (' + sixteenths + '/16")';
    }
    var nearestBit = function(d) { var s = Math.round(d * 64) / 64; return fmt(s, 4) + '" (' + Math.round(s * 64) + '/64")'; };
    document.getElementById('screwLength').textContent = fmt(recLength, 2) + '"';
    document.getElementById('pilotHole').textContent = nearestBit(pilot);
    document.getElementById('clearanceHole').textContent = nearestBit(clearance);
    document.getElementById('countersink').textContent = nearestBit(counter);
